import{_ as a,o as t,c as i,ag as n}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"Proxy Smart — Documentation","description":"","frontmatter":{"layout":"home","hero":{"name":"Proxy Smart","text":"Healthcare Interoperability Proxy","tagline":"SMART App Launch 2.2.0, OAuth 2.0, MCP Server & AI-Powered Admin","actions":[{"theme":"brand","text":"Get Started","link":"/admin-ui/dashboard"},{"theme":"alt","text":"MCP & AI","link":"/MCP_HTTP_SERVER"}]},"features":[{"title":"SMART App Launch 2.2.0","details":"Full OAuth 2.0 with PKCE, JWT validation, scope-based access control, and refresh token rotation."},{"title":"Stateless FHIR Proxy","details":"No clinical data stored — requests pass through to your FHIR servers with full audit logging."},{"title":"MCP Server","details":"Streamable HTTP endpoint at /mcp exposing all admin tools and documentation search to AI clients."},{"title":"AI Assistant & RAG","details":"Built-in assistant with semantic documentation search powered by OpenAI embeddings."},{"title":"Admin Dashboard","details":"React UI for managing apps, users, servers, scopes, identity providers, and consent."},{"title":"Medical Imaging","details":"DICOMweb proxy with QIDO-RS & WADO-RS, Patient Portal imaging viewer powered by Cornerstone3D."},{"title":"Docker-Ready","details":"Mono-container and multi-container deployments with automatic version management."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),o={name:"index.md"};function r(s,e,l,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="proxy-smart-—-documentation" tabindex="-1">Proxy Smart — Documentation <a class="header-anchor" href="#proxy-smart-—-documentation" aria-label="Permalink to &quot;Proxy Smart — Documentation&quot;">​</a></h1><p>Comprehensive documentation for the Proxy Smart platform: a stateless FHIR proxy with OAuth 2.0, SMART App Launch 2.2.0, and an intelligent admin interface.</p><h2 id="platform-overview" tabindex="-1">Platform Overview <a class="header-anchor" href="#platform-overview" aria-label="Permalink to &quot;Platform Overview&quot;">​</a></h2><p>Proxy Smart sits between SMART apps and FHIR servers, handling authentication and authorization without storing clinical data. It includes an admin dashboard, AI assistant with RAG-powered documentation search, MCP server integration, consent management, and access control.</p><h3 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h3><ul><li><strong>SMART App Launch 2.2.0</strong> — Full OAuth 2.0 with PKCE, JWT validation, scope-based access control, refresh token rotation</li><li><strong>Stateless FHIR Proxy</strong> — No clinical data stored; requests pass through to your FHIR servers</li><li><strong>Admin Dashboard</strong> — React UI for managing apps, users, servers, scopes, and identity providers</li><li><strong>AI Assistant &amp; RAG</strong> — Built-in assistant with semantic documentation search (<code>search_documentation</code> tool)</li><li><strong>MCP Server</strong> — Streamable HTTP endpoint at <code>/mcp</code> exposing all admin tools + documentation search</li><li><strong>Consent Management</strong> — Patient consent app for authorization flows (<code>consent-app/</code>)</li><li><strong>DTR App</strong> — Documentation, Templates &amp; Rules app (<code>dtr-app/</code>)</li><li><strong>Medical Imaging</strong> — DICOMweb proxy (QIDO-RS &amp; WADO-RS) with Cornerstone3D viewer in the Patient Portal</li><li><strong>Access Control</strong> — Physical access integrations (Kisi, UniFi Access)</li><li><strong>AI Skills System</strong> — Installable skills for extending AI assistant capabilities</li><li><strong>Docker-Ready</strong> — Mono-container and multi-container deployments</li></ul><h2 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h2><h3 id="admin-ui" tabindex="-1">Admin UI <a class="header-anchor" href="#admin-ui" aria-label="Permalink to &quot;Admin UI&quot;">​</a></h3><ul><li><a href="./admin-ui/dashboard">Dashboard Overview</a> — System overview and health monitoring</li><li><a href="./admin-ui/user-management">User Management</a> — Healthcare users and FHIR associations</li><li><a href="./admin-ui/smart-apps">SMART Apps</a> — Application registration and management</li><li><a href="./admin-ui/fhir-servers">FHIR Servers</a> — Server configuration and monitoring</li><li><a href="./admin-ui/scope-management">Scope Management</a> — FHIR permissions and templates</li><li><a href="./admin-ui/access-control">Access Control</a> — Physical door management (Kisi, UniFi Access)</li><li><a href="./admin-ui/monitoring">Monitoring &amp; Observability</a> — OAuth, FHIR health, consent, and audit monitoring</li></ul><h3 id="ai-mcp" tabindex="-1">AI &amp; MCP <a class="header-anchor" href="#ai-mcp" aria-label="Permalink to &quot;AI &amp; MCP&quot;">​</a></h3><ul><li><a href="./MCP_HTTP_SERVER">MCP HTTP Server</a> — Streamable HTTP endpoint architecture and usage</li><li><a href="./AI_MCP_INTEGRATION">AI MCP Integration</a> — How the AI assistant connects to MCP servers</li><li><a href="./BACKEND_API_TOOLS">Backend API Tools</a> — Auto-generated tools from Elysia routes</li><li><a href="./BACKEND_MCP_HTTP_CLIENT">Backend MCP HTTP Client</a> — HTTP-based MCP client</li><li><a href="./BACKEND_MCP_STREAMABLE_CLIENT">Backend MCP Streamable Client</a> — Streamable HTTP MCP client</li><li><a href="./AI_INTERACTIVE_ACTIONS">AI Interactive Actions</a> — Interactive action system</li><li><a href="./ai/ADDING_CUSTOM_TOOLS">Adding Custom Tools</a> — Guide for adding custom AI tools</li><li><a href="./ai/action-quick-reference">Action Quick Reference</a> — AI action reference card</li><li><a href="./ai/interactive-actions">Interactive Actions Guide</a> — Detailed interactive actions docs</li></ul><h3 id="imaging-dicomweb" tabindex="-1">Imaging &amp; DICOMweb <a class="header-anchor" href="#imaging-dicomweb" aria-label="Permalink to &quot;Imaging &amp; DICOMweb&quot;">​</a></h3><ul><li><a href="./dicomweb-proxy">DICOMweb Proxy</a> — QIDO-RS &amp; WADO-RS proxy endpoints, authentication, and deployment</li><li><a href="./patient-portal-imaging">Patient Portal Imaging</a> — ImagingStudy cards, Cornerstone3D viewer, and DICOMweb client library</li></ul><h3 id="smart-on-fhir" tabindex="-1">SMART on FHIR <a class="header-anchor" href="#smart-on-fhir" aria-label="Permalink to &quot;SMART on FHIR&quot;">​</a></h3><ul><li><a href="./SMART_2.2.0_CHECKLIST">SMART 2.2.0 Implementation Checklist</a> — Spec compliance status</li></ul><h3 id="guides" tabindex="-1">Guides <a class="header-anchor" href="#guides" aria-label="Permalink to &quot;Guides&quot;">​</a></h3><ul><li><a href="./tutorials/version-management">Version Management</a> — Branching, versioning, and releases</li></ul><h2 id="ai-assistant" tabindex="-1">AI Assistant <a class="header-anchor" href="#ai-assistant" aria-label="Permalink to &quot;AI Assistant&quot;">​</a></h2><p>The platform includes an AI assistant powered by RAG (Retrieval Augmented Generation). It indexes all documentation in this <code>docs/</code> directory using OpenAI embeddings and serves relevant context via:</p><ul><li><strong>AI chat tool</strong> — <code>search_documentation</code> called by the assistant during conversations</li><li><strong>MCP endpoint</strong> — Available to external MCP clients at <code>/mcp</code></li><li><strong>Public HTTP API</strong> — <code>GET /docs/search/semantic?q=...</code> for direct access</li></ul><p>The assistant can answer questions about SMART on FHIR, platform configuration, OAuth flows, and admin operations using up-to-date documentation.</p><h2 id="additional-resources" tabindex="-1">Additional Resources <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;Additional Resources&quot;">​</a></h2><ul><li><a href="https://hl7.org/fhir/smart-app-launch/" target="_blank" rel="noreferrer">SMART App Launch Framework</a></li><li><a href="https://hl7.org/fhir/R4/" target="_blank" rel="noreferrer">FHIR R4 Specification</a></li><li><a href="https://tools.ietf.org/html/rfc6749" target="_blank" rel="noreferrer">OAuth 2.0 RFC</a></li><li><a href="https://openid.net/connect/" target="_blank" rel="noreferrer">OpenID Connect</a></li></ul><hr><p><em>This documentation is indexed by the RAG knowledge base for AI-powered search.</em></p>',25)])])}const p=a(o,[["render",r]]);export{u as __pageData,p as default};
